module cache_mshr #(
    parameter_INSTANCE_ID                   = "mo_mshr"             ,
    parameter MSHR_SIZE                     = 32                    ,
    parameter CS_LINE_ADDR_WIDTH            = 10                    ,
    parameter WORD_SEL_WIDTH                = 4                     ,
    parameter WORD_SIZE                     = 4                     ,
    // Derived parameters
    parameter MSHR_ADDR_WIDTH               = $clog2(MSHR_SIZE)     , // default = 5
    parameter TAG_WIDTH                     = 32 - (CS_LINE_ADDR_WIDTH+ $clog2(WORD_SIZE) + WORD_SEL_WIDTH), // default = 16
    parameter CS_WORD_WIDTH                 = WORD_SIZE * 8 ,// default = 32 
    parameter DATA_WIDTH                    = WORD_SEL_WIDTH + WORD_SIZE + CS_WORD_WIDTH + TAG_WIDTH // default =  4 + 4 + 32 + 16 = 56

    ) (
    input wire clk,
    input wire reset,

    // allocate
    input wire                          allocate_valid,
    output wire                         allocate_ready,
    input wire [CS_LINE_ADDR_WIDTH-1:0] allocate_addr,
    input wire                          allocate_rw,
    input wire [DATA_WIDTH-1:0]         allocate_data,
    output wire [MSHR_ADDR_WIDTH-1:0]   allocate_id,
    output wire                         allocate_pending,
    output wire [MSHR_ADDR_WIDTH-1:0]   allocate_previd,

    // finalize
    input wire                          finalize_valid,
    input wire [MSHR_ADDR_WIDTH-1:0]    finalize_id
);

    // Generated ports
    reg [MSHR_ADDR_WIDTH-1:0] allocate_idx;
    reg [MSHR_ADDR_WIDTH-1:0] allocate_prev_idx;
    reg [MSHR_ADDR_WIDTH-1:0] allocate_next_idx;

    // Leading zero counter
    leading_zero_cnt #(
            .DATA_WIDTH (MSHR_SIZE),
            .REVERSE (1)
    ) allocate_idx (
            .data   (~entry_valid_table_q), // bit-wise invert for available slots
            .leading_zeros  (allocate_id_d),
            .all_zeros (full_d)
    );

    leading_zero_cnt #(
            .DATA_WIDTH (MSHR_SIZE),
            .REVERSE (1)
    ) allocate_prev_idx (
            .data   (match_with_no_next), // allocate address matches that doesn't have next address pointer
            .leading_zeros  (prev_idx),
            `NOTCONNECTED_PIN(all_zeros) // not connected
    );

    // Implement allocation logic
    always@* begin
        if (allocate_valid && !reset) begin
            // Allocate first available slot
            allocate_ready = 1;
            allocate_id = allocate_idx;
            allocate_pending = (allocate_id == allocate_prev_idx);
        end
    end

    // Implement finalize logic
    always@* begin
        if (finalizer_valid && !reset) begin
            // Finalize allocated slot
            entry_valid_table_q = 0;
            // Update next index if there is a next entry
            if (allocate_next_idx != -1) begin
                next_idx_next = next_idx + 1;
                next_idx_next = next_idx_next & (MSHR_SIZE - 1);
